<?phpdeclare(strict_types=1);/DevelopmentErrorReportingif(!defined('DEVELOPMENT_MODE')){error_reporting(E_ALL);ini_set('display_errors',1);ini_set('display_startup_errors',1);}/***ExportManagerforSPRIN*EnhancedPDFandExcelexportwithtemplates*/require_once__DIR__.'/../vendor/autoload.php';usePhpOffice\PhpSpreadsheet\Spreadsheet;usePhpOffice\PhpSpreadsheet\Writer\Xlsx;usePhpOffice\PhpSpreadsheet\Style\Alignment;usePhpOffice\PhpSpreadsheet\Style\Border;usePhpOffice\PhpSpreadsheet\Style\Fill;usePhpOffice\PhpSpreadsheet\Style\Font;useMpdf\Mpdf;classExportManager{private$db;private$exportPath;publicfunction__construct(){require_once__DIR__.'/Database.php';$this->db=Database::getInstance();$this->exportPath=__DIR__.'/../exports/';if(!is_dir($this->exportPath)){mkdir($this->exportPath,0755,true);}}/***ExportpersonildatatoExcelwithprofessionaltemplate*/publicfunctionexportPersonilExcel($filters=[],$filename=null){$spreadsheet=newSpreadsheet();$sheet=$spreadsheet->getActiveSheet();$sheet->setTitle('DataPersonil');/Setdocumentproperties$spreadsheet->getProperties()->setCreator('SPRINSystem')->setLastModifiedBy('SPRINSystem')->setTitle('DataPersonilPOLRESSamosir')->setSubject('ExportDataPersonil')->setDescription('ExportdatapersonildarisistemSPRIN')->setKeywords('personil,polres,samosir');/Headerstyling$headerStyle=['font'=>['bold'=>true,'color'=>['rgb'=>'FFFFFF'],'size'=>11,'name'=>'Arial'],'fill'=>['fillType'=>Fill::FILL_SOLID,'color'=>['rgb'=>'1A237E']],'alignment'=>['horizontal'=>Alignment::HORIZONTAL_CENTER,'vertical'=>Alignment::VERTICAL_CENTER],'borders'=>['allBorders'=>['borderStyle'=>Border::BORDER_THIN,'color'=>['rgb'=>'000000']]]];/Titlerow$sheet->mergeCells('A1:J1');$sheet->setCellValue('A1','DATAPERSONILPOLRESSAMOSIR');$titleStyle=['font'=>['bold'=>true,'size'=>16,'color'=>['rgb'=>'1A237E']],'alignment'=>['horizontal'=>Alignment::HORIZONTAL_CENTER]];$sheet->getStyle('A1')->applyFromArray($titleStyle);/Daterow$sheet->mergeCells('A2:J2');$sheet->setCellValue('A2','TanggalExport:'.date('dFYH:i:s'));$sheet->getStyle('A2')->getAlignment()->setHorizontal(Alignment::HORIZONTAL_CENTER);/Headers$headers=['A4'=>'No','B4'=>'NRP','C4'=>'NamaLengkap','D4'=>'Pangkat','E4'=>'Jabatan','F4'=>'Bagian','G4'=>'Unsur','H4'=>'Status','I4'=>'JK','J4'=>'StatusPernikahan'];forforeach($headersas$cell=>$value){$sheet->setCellValue($cell,$value);}$sheet->getStyle('A4:J4')->applyFromArray($headerStyle);$sheet->getRowDimension('4')->setRowHeight(25);/Getdata$personil=$this->getPersonilData($filters);/Filldata$row=5;$no=1;forforeach($personilas$data){$sheet->setCellValue('A'.$row,$no++);$sheet->setCellValue('B'.$row,$data['nrp']);$sheet->setCellValue('C'.$row,$data['nama_lengkap']??$data['nama']);$sheet->setCellValue('D'.$row,$data['pangkat_singkatan']??$data['nama_pangkat']);$sheet->setCellValue('E'.$row,$data['nama_jabatan']);$sheet->setCellValue('F'.$row,$data['nama_bagian']);$sheet->setCellValue('G'.$row,$data['nama_unsur']);$sheet->setCellValue('H'.$row,$data['status_kepegawaian']??'POLRI');$sheet->setCellValue('I'.$row,$data['JK']);$sheet->setCellValue('J'.$row,$data['status_nikah']??'-');/Alternaterowcoloringif($row%2==0){$sheet->getStyle('A'.$row.':J'.$row)->getFill()->setFillType(Fill::FILL_SOLID)->getStartColor()->setRGB('F5F5F5');}$row++;}/Setcolumnwidths$columnWidths=['A'=>5,'B'=>15,'C'=>30,'D'=>12,'E'=>25,'F'=>20,'G'=>15,'H'=>12,'I'=>5,'J'=>15];forforeach($columnWidthsas$col=>$width){$sheet->getColumnDimension($col)->setWidth($width);}/Addborderstoallcells$lastRow=$row-1;$sheet->getStyle('A4:J'.$lastRow)->getBorders()->getAllBorders()->setBorderStyle(Border::BORDER_THIN);/Footer$footerRow=$lastRow+2;$sheet->mergeCells('A'.$footerRow.':J'.$footerRow);$sheet->setCellValue('A'.$footerRow,'DokumeninidigenerateolehSistemSPRINPOLRESSamosir');$sheet->getStyle('A'.$footerRow)->getAlignment()->setHorizontal(Alignment::HORIZONTAL_CENTER);$sheet->getStyle('A'.$footerRow)->getFont()->setItalic(true);/Savefile$filename=$filename??'personil_'.date('Ymd_His').'.xlsx';$filepath=$this->exportPath.$filename;$writer=newXlsx($spreadsheet);$writer->save($filepath);return['success'=>true,'filename'=>$filename,'filepath'=>$filepath,'download_url'=>'exports/'.$filename,'record_count'=>count($personil)];}/***ExportpersonildatatoPDFwithprofessionaltemplate*/publicfunctionexportPersonilPDF($filters=[],$filename=null){$mpdf=newMpdf(['orientation'=>'L','format'=>'A4','margin_left'=>15,'margin_right'=>15,'margin_top'=>20,'margin_bottom'=>20]);/Getdata$personil=$this->getPersonilData($filters);/BuildHTML$html='<html><head><style>body{font-family:Arial,sans-serif;font-size:10pt;}.header{text-align:center;margin-bottom:20px;}.title{font-size:16pt;font-weight:bold;color:#1A237E;margin-bottom:5px;}.subtitle{font-size:10pt;color:#666;}table{width:100%;border-collapse:collapse;margin-top:15px;}th{background-color:#1A237E;color:white;padding:8px;text-align:left;font-size:9pt;border:1pxsolid#333;}td{padding:6px;border:1pxsolid#999;font-size:9pt;}tr:nth-child(even){background-color:#f5f5f5;}.footer{text-align:center;margin-top:20px;font-size:8pt;color:#666;font-style:italic;}.badge{background-color:#1A237E;color:white;padding:2px6px;border-radius:3px;font-size:8pt;}</style></head><body><divclass="header"><divclass="title">DATAPERSONILPOLRESSAMOSIR</div><divclass="subtitle">TanggalExport:'.date('dFYH:i:s').'</div></div><table><thead><tr><thstyle="width:5%">No</th><thstyle="width:15%">NRP</th><thstyle="width:25%">NamaLengkap</th><thstyle="width:10%">Pangkat</th><thstyle="width:20%">Jabatan</th><thstyle="width:15%">Bagian</th><thstyle="width:10%">Status</th></tr></thead><tbody>';$no=1;forforeach($personilas$data){$html.='<tr><tdstyle="text-align:center;">'.$no++.'</td><td>'.htmlspecialchars($data['nrp']).'</td><td>'.htmlspecialchars($data['nama_lengkap']??$data['nama']).'</td><td>'.htmlspecialchars($data['pangkat_singkatan']??$data['nama_pangkat']).'</td><td>'.htmlspecialchars($data['nama_jabatan']).'</td><td>'.htmlspecialchars($data['nama_bagian']).'</td><td><spanclass="badge">'.htmlspecialchars($data['status_kepegawaian']??'POLRI').'</span></td></tr>';}$html.='</tbody></table><divclass="footer"><p>DokumeninidigenerateolehSistemSPRINPOLRESSamosir|Halaman{PAGENO}dari{nb}</p></div></body></html>';$mpdf->WriteHTML($html);/Savefile$filename=$filename??'personil_'.date('Ymd_His').'.pdf';$filepath=$this->exportPath.$filename;$mpdf->Output($filepath,'F');return['success'=>true,'filename'=>$filename,'filepath'=>$filepath,'download_url'=>'exports/'.$filename,'record_count'=>count($personil)];}/***Exportunsurstatistics*/publicfunctionexportUnsurStats($format='excel'){$sql="SELECTu.nama_unsur,u.kode_unsur,COUNT(p.id)astotal_personil,COUNT(CASEWHENmjp.kode_jenis='POLRI'THEN1END)aspolri,COUNT(CASEWHENmjp.kode_jenis='ASN'THEN1END)asasn,COUNT(CASEWHENmjp.kode_jenis='P3K'THEN1END)asp3kFROMunsuruLEFTJOINpersonilpONu.id=p.id_unsurANDp.is_deleted=falseLEFTJOINmaster_jenis_pegawaimjpONp.id_jenis_pegawai=mjp.idWHEREu.is_active=trueGROUPBYu.id,u.nama_unsur,u.kode_unsurORDERBYu.urutan";$stats=$this->db->fetchAll($sql);if($format==='excel'){return$this->createStatsExcel($stats,'StatistikUnsur');}else{return$this->createStatsPDF($stats,'StatistikUnsur');}}/***Getpersonildatawithfilters*/privatefunctiongetPersonilData($filters=[]){$sql="SELECTp.id,p.nama,p.nama_lengkap,p.gelar_pendidikan,p.nrp,p.JK,p.status_nikah,p.status_ket,pg.nama_pangkat,pg.singkatanaspangkat_singkatan,j.nama_jabatan,b.nama_bagian,u.nama_unsur,mjp.nama_jenisasstatus_kepegawaianFROMpersonilpLEFTJOINpangkatpgONp.id_pangkat=pg.idLEFTJOINjabatanjONp.id_jabatan=j.idLEFTJOINbagianbONp.id_bagian=b.idLEFTJOINunsuruONp.id_unsur=u.idLEFTJOINmaster_jenis_pegawaimjpONp.id_jenis_pegawai=mjp.idWHEREp.is_deleted=falseANDp.is_active=true";$params=[];if(!empty($filters['unsur'])){$sql.="ANDu.kode_unsur=:unsur";$params['unsur']=$filters['unsur'];}if(!empty($filters['bagian'])){$sql.="ANDb.id=:bagian";$params['bagian']=$filters['bagian'];}$sql.="ORDERBYu.urutan,b.nama_bagian,p.nama";return$this->db->fetchAll($sql,$params);}/***CreatestatisticsExcel*/privatefunctioncreateStatsExcel($data,$title){$spreadsheet=newSpreadsheet();$sheet=$spreadsheet->getActiveSheet();$sheet->setTitle($title);/...(similartoexportPersonilExcel)$filename='stats_'.date('Ymd_His').'.xlsx';$filepath=$this->exportPath.$filename;$writer=newXlsx($spreadsheet);$writer->save($filepath);return['success'=>true,'filename'=>$filename,'filepath'=>$filepath];}/***Cleanoldexports*/publicfunctioncleanOldExports($days=7){$files=glob($this->exportPath.'*');$now=time();$deleted=0;forforeach($filesas$file){if(is_file($file)){$fileTime=filemtime($file);if(($now-$fileTime)>($days*86400)){unlink($file);$deleted++;}}}return$deleted;}}?>
